// src/App.js
import React, { useEffect } from "react";
import { useNodesState, useEdgesState } from "reactflow";
import { PipelineToolbar } from "./toolbar";
import { PipelineUI } from "./ui";
import FlowCanvas from "./FlowCanvas";

/**
 * Apply reactflow-style edge change objects to a previous edges array.
 * Handles types: add, remove, update, reset.
 */
function applyEdgeChanges(changes = [], prevEdges = []) {
  let next = [...prevEdges];

  for (const ch of changes || []) {
    const { type, item } = ch;
    if (!type) continue;

    if (type === "add" && item) {
      if (!next.find((e) => e.id === item.id)) next.push(item);
    } else if (type === "remove" && item) {
      next = next.filter((e) => e.id !== item.id);
    } else if (type === "reset" && Array.isArray(ch.items)) {
      next = [...ch.items];
    } else if (type === "update" && item) {
      next = next.map((e) => (e.id === item.id ? { ...e, ...item } : e));
    }
  }

  return next;
}

export default function App() {
  const [nodes, setNodes, onNodesChange] = useNodesState([
    { id: "1", type: "inputNode", position: { x: 50, y: 50 }, data: {} },
    { id: "2", type: "llmNode", position: { x: 300, y: 50 }, data: {} },
    { id: "3", type: "textNode", position: { x: 50, y: 200 }, data: {} },
    { id: "4", type: "outputNode", position: { x: 300, y: 200 }, data: {} },
    {
      id: "5",
      type: "deleteNode",
      position: { x: 550, y: 125 },
      data: { incoming: null, onDelete: () => {} },
    },
  ]);

  const [edges, setEdges, onEdgesChange] = useEdgesState([
    { id: "e1-2", source: "1", target: "2" },
    { id: "e3-2", source: "3", target: "2" },
    { id: "e2-4", source: "2", target: "4" },
  ]);

  // Delete handler: removes target node and the delete node (id "5")
  const handleDeleteNode = (targetId) => {
    console.log("handleDeleteNode called with targetId:", targetId);
    if (!targetId) return;

    setNodes((nds) => nds.filter((n) => n.id !== targetId && n.id !== "5"));
    setEdges((eds) =>
      eds.filter(
        (e) =>
          e.source !== targetId &&
          e.target !== targetId &&
          e.source !== "5" &&
          e.target !== "5"
      )
    );
  };

  // Ensure delete node has onDelete injected on mount (defensive)
  useEffect(() => {
    setNodes((nds) =>
      nds.map((n) =>
        n.id === "5" ? { ...n, data: { ...n.data, onDelete: handleDeleteNode } } : n
      )
    );
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // run once

  // Called when user creates a connection via UI
  const handleConnect = (params) => {
    const newEdge = {
      id: params.id || `e${params.source}-${params.target}-${Date.now()}`,
      source: params.source,
      target: params.target,
      ...params,
    };

    setEdges((prev) => {
      const next = [...prev, newEdge];

      // immediate update if connecting to delete node
      if (newEdge.target === "5") {
        setNodes((nds) =>
          nds.map((n) =>
            n.id === "5"
              ? { ...n, data: { ...n.data, incoming: newEdge.source, onDelete: handleDeleteNode } }
              : n
          )
        );
      }

      return next;
    });
  };

  // Intercept edge changes (selection, removal, batch updates) and compute new edges snapshot.
  // We call the reactflow helper onEdgesChange(changes) so reactflow internal state updates,
  // then we also update our edges state from the applied changes and keep deleteNode.data.incoming in sync.
  const handleEdgesChange = (changes) => {
    // let reactflow update its internal state
    onEdgesChange(changes);

    // compute the new edges snapshot from previous edges + changes
    setEdges((prevEdges) => {
      const nextEdges = applyEdgeChanges(changes, prevEdges);

      // find any edge that targets delete node id "5"
      const incomingEdge = nextEdges.find((e) => e.target === "5");
      const incoming = incomingEdge ? incomingEdge.source : null;

      // update delete node's data.incoming and onDelete
      setNodes((nds) =>
        nds.map((n) =>
          n.id === "5"
            ? { ...n, data: { ...n.data, incoming, onDelete: handleDeleteNode } }
            : n
        )
      );

      // debug logs
      console.log("Applied edge changes:", changes);
      console.log("Next edges:", nextEdges);
      console.log("DeleteNode incoming:", incoming);

      return nextEdges;
    });
  };

  return (
    <div>
      <PipelineToolbar />
      <PipelineUI />
      <FlowCanvas
        nodes={nodes}
        edges={edges}
        onNodesChange={onNodesChange}
        onEdgesChange={handleEdgesChange} // <-- use our handler here
        onConnect={handleConnect}
      />
    </div>
  );
}
